settings._cssCustom:
/* ### 
   ### Blocks > Breadcrumbs
   ###
*/

.rank-math-breadcrumb p {
    font-size: var(--at-text--2xs);
    font-weight: 300;
}

.rank-math-breadcrumb a::first-letter {
  text-transform: uppercase;
}

.rank-math-breadcrumb a {
	color: #333;
  display: inline-block;
}

.rank-math-breadcrumb a:hover {
	color: #666;
}

/* ### 
   ### COMPARATIF PRODUITS
   ###
*/

.comparatif-up {
  color:var(--at-secondary);
  font-size:var(--at-text--xs);
      margin: 0;
}

/* ### 
   ### Blocks > Post-meta
   ###
*/

.titre-principal {
  line-height: 1.3;
  text-align:left;
  text-wrap: auto;
  margin:0;
  font-family: 'source serif 4';
}

.titre-principal span {
    font-weight:300;
}

p.marques-evaluees {
  font-size: var(--at-text--xl);
}

.text-content {

  h2, h3, h4, h5, h6{
  	font-weight: 700;
    color: var(--at-black);
    margin-bottom: var(--at-space--s);
  }

  h2{
  	font-size: var(--at-heading--m);
  }

  h3{
    font-size: var(--at-heading--s);
  }

  h4, h5, h6{
  	font-size: var(--at-text--s);
  }

  p {

    strong, bold{
      color: var(--at-black);
    }

    a{
     	color: var(--at-primary);
      transition: color .2s ease;

      &:hover, &:focus{
      	color: var(--at-primary-d-1);
        text-decoration: underline;
      }
    }

  }

  ul, ol{
    margin:var(--at-space--m) 0;

    ::marker{
      color: var(--at-black);
    }

    li:not(:last-child){
    	margin-bottom: 8px;
    }
  }
}
